const sd = $getWorkflowStaticData('global');
const mode = String($json.mode);
const ingredients = ($json.ingredients || '').trim();

const now = new Date();
const yyyy = now.getFullYear();
const mm = String(now.getMonth() + 1).padStart(2, '0');
const dd = String(now.getDate()).padStart(2, '0');
const today = `${yyyy}-${mm}-${dd}`;

const history = (sd.history || []).slice(-7);
const banned = (sd.banned || []);

const modeDesc = mode === '1' ? 'Evdeki malzemelere göre' : (mode === '3' ? 'Hafif' : 'Direkt öner');

const prompt = `Sen bir akşam yemeği asistanısın. 3 kişilik sağlıklı ev yemeği öner.

KURALLAR (kullanıcı günceller):\n${sd.rules}\n
AMAÇLAR:
- Dengeli beslenme.
- 1 hafta içinde protein kaynakları çeşitlensin (tavuk/balık/kırmızı et/bakliyat/vejetaryen).
- Üst üste aynı/çok benzer yemeği önermeyin (son 7 öneriye bak).
- Yasaklıları asla önermeyin.
- Çıktıyı SADECE geçerli JSON olarak ver (markdown yok).

YASAKLILAR: ${banned.length ? banned.join(', ') : 'yok'}
SON ÖNERİLER (son 7): ${history.length ? history.map(h => `${h.date}:${h.title}`).join(' | ') : 'yok'}

MOD: ${modeDesc}
${mode === '1' ? `EVDEKİ MALZEMELER: ${ingredients}` : ''}

ÇIKTI JSON ŞEMASI:
{
  "title": "...",
  "proteinTag": "tavuk|balık|kırmızı_et|bakliyat|vejetaryen|karışık",
  "prepMinutes": 30,
  "ingredients": ["..."],
  "steps": ["..."],
  "nutritionNote": "kısa not",
  "shoppingNeeded": ["..."],
  "whyThis": "1 cümle",
  "lightLevel": "hafif|orta"
}
`;

return [{ json: { today, mode, prompt } }];

const sd = $getWorkflowStaticData('global');
const today = $node["Build prompt (Ollama)"].json.today;
const mode = $node["Build prompt (Ollama)"].json.mode;

let candidate = $json.response;
if (!candidate && $json.body?.response) candidate = $json.body.response;

let obj;
try {
  obj = JSON.parse(candidate);
} catch (e) {
  const m = String(candidate || '').match(/\{[\s\S]*\}/);
  if (!m) throw e;
  obj = JSON.parse(m[0]);
}

if (!sd.history) sd.history = [];
sd.history.push({ date: today, title: obj.title, proteinTag: obj.proteinTag, mode });
sd.history = sd.history.slice(-30);

return [{ json: { obj } }];

const o = $json.obj;

const ing = (o.ingredients || []).map(x => `• ${x}`).join('
');
const steps = (o.steps || []).map((x, i) => `${i + 1}) ${x}`).join('
');
const shop = (o.shoppingNeeded || []);
const shopText = shop.length ? shop.map(x => `• ${x}`).join('
') : '• Yok / mevcutlarla olur';

const msg = `🍽️ *${o.title}*

` +
  `🏷️ Protein: *${o.proteinTag}* | Hafiflik: *${o.lightLevel || 'orta'}*
` +
  `⏱️ Hazırlık: *${o.prepMinutes} dk*

` +
  `🧺 Malzemeler:
${ing || '• (liste yok)'}

` +
  `🛒 Alışveriş Gerekir mi?
${shopText}

` +
  `👩‍🍳 Yapılış:
${steps || '(adım yok)'}

` +
  `✅ Neden bu? ${o.whyThis || ''}
` +
  `🥗 Beslenme notu: ${o.nutritionNote || ''}`;

return [{ json: { text: msg } }];
